mapper.select:
SELECT * FROM rank_data
WHERE rank_type = #{rankType}
ORDER BY score DESC, update_time ASC
LIMIT #{limit}

mapper.update:
UPDATE rank_data rd
JOIN (
    SELECT id, ROW_NUMBER() OVER (ORDER BY score DESC, update_time ASC) as new_rank
    FROM rank_data
    WHERE rank_type = #{rankType}
) as ranked ON rd.id = ranked.id
SET rd.rank_num = ranked.new_rank
WHERE rd.rank_type = #{rankType}
